.darma-loader-darma-custom-617 {color: var(--loader-color, #6d28d9);
   height: 50px;
   aspect-ratio: 2;
   border: 8px solid currentColor;
   box-sizing: border-box;
   background: radial-gradient(farthest-side,currentColor 98%,#0000) left/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) left/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) center/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) right/20px 20px, currentColor;
   background-repeat: no-repeat;
   filter: blur(4px) contrast(10);
   animation: darma-loader-darma-custom-617-l14 1s infinite;
}
@keyframes darma-loader-darma-custom-617-l14  {
  100% {background-position:right,left,center,right}
}

